import { useCallback, useEffect, useRef, useState } from 'react';

export interface ChunkedUploadOptions {
  /** Chunk size in bytes. Default is 5MB. */
  chunkSize?: number;
  /** API endpoint that accepts and finalizes uploaded chunks. */
  uploadUrl: string;
  /** Callback fired with the final chunk response after the upload completes. */
  onSuccess?: (response: Response) => void;
  /** Callback fired if validation or a chunk upload fails. */
  onError?: (error: Error) => void;
  /** Callback fired after a chunk completes, with byte-based progress (0-100). */
  onProgress?: (progress: number) => void;
}

export interface ChunkedUploadState {
  progress: number;
  isUploading: boolean;
  isPaused: boolean;
  isError: boolean;
  isSuccess: boolean;
}

interface UploadSession {
  file: File;
  uploadId: string;
  chunkSize: number;
  uploadUrl: string;
}

const initialState: ChunkedUploadState = {
  progress: 0,
  isUploading: false,
  isPaused: false,
  isError: false,
  isSuccess: false,
};

function createUploadId(): string {
  if (typeof crypto !== 'undefined' && typeof crypto.randomUUID === 'function') {
    return crypto.randomUUID();
  }

  return `${Date.now()}-${Math.random().toString(36).slice(2)}`;
}

function toError(error: unknown): Error {
  return error instanceof Error ? error : new Error(String(error));
}

export function useChunkedUpload(options: ChunkedUploadOptions) {
  const {
    chunkSize = 5 * 1024 * 1024,
    uploadUrl,
    onSuccess,
    onError,
    onProgress,
  } = options;

  const [state, setState] = useState<ChunkedUploadState>(initialState);
  const sessionRef = useRef<UploadSession | null>(null);
  const currentChunkIndexRef = useRef(0);
  const abortControllerRef = useRef<AbortController | null>(null);
  const runIdRef = useRef(0);
  const isRunningRef = useRef(false);
  const isPausedRef = useRef(false);

  const uploadChunks = useCallback(async (runId: number) => {
    const session = sessionRef.current;

    if (!session || runId !== runIdRef.current) return;

    const { file, uploadId, chunkSize: sessionChunkSize, uploadUrl: sessionUploadUrl } = session;
    const totalChunks = Math.max(1, Math.ceil(file.size / sessionChunkSize));
    let finalResponse: Response | null = null;

    try {
      while (
        currentChunkIndexRef.current < totalChunks &&
        runId === runIdRef.current &&
        !isPausedRef.current
      ) {
        const chunkIndex = currentChunkIndexRef.current;
        const start = chunkIndex * sessionChunkSize;
        const end = Math.min(start + sessionChunkSize, file.size);
        const formData = new FormData();

        formData.append('file', file.slice(start, end));
        formData.append('filename', file.name);
        formData.append('uploadId', uploadId);
        formData.append('chunkIndex', chunkIndex.toString());
        formData.append('totalChunks', totalChunks.toString());

        const controller = new AbortController();
        abortControllerRef.current = controller;

        const response = await fetch(sessionUploadUrl, {
          method: 'POST',
          body: formData,
          signal: controller.signal,
        });

        if (!response.ok) {
          throw new Error(`Chunk upload failed with status: ${response.status}`);
        }

        if (runId !== runIdRef.current || isPausedRef.current) return;

        finalResponse = response;
        currentChunkIndexRef.current = chunkIndex + 1;

        const uploadedBytes = Math.min(currentChunkIndexRef.current * sessionChunkSize, file.size);
        const progress = file.size === 0 ? 100 : Math.round((uploadedBytes / file.size) * 100);
        setState(current => ({ ...current, progress }));
        onProgress?.(progress);
      }

      if (
        runId === runIdRef.current &&
        !isPausedRef.current &&
        currentChunkIndexRef.current >= totalChunks &&
        finalResponse
      ) {
        isRunningRef.current = false;
        abortControllerRef.current = null;
        setState(current => ({
          ...current,
          progress: 100,
          isUploading: false,
          isPaused: false,
          isError: false,
          isSuccess: true,
        }));
        onSuccess?.(finalResponse);
      }
    } catch (error: unknown) {
      if (runId !== runIdRef.current) return;

      isRunningRef.current = false;
      abortControllerRef.current = null;

      if (error instanceof Error && error.name === 'AbortError') {
        return;
      }

      const uploadError = toError(error);
      setState(current => ({
        ...current,
        isUploading: false,
        isPaused: false,
        isError: true,
        isSuccess: false,
      }));
      onError?.(uploadError);
    }
  }, [onError, onProgress, onSuccess]);

  const reportValidationError = useCallback((message: string) => {
    const error = new Error(message);
    setState({
      ...initialState,
      isError: true,
    });
    onError?.(error);
  }, [onError]);

  const startUpload = useCallback((file: File) => {
    runIdRef.current += 1;
    isRunningRef.current = false;
    abortControllerRef.current?.abort();
    abortControllerRef.current = null;
    sessionRef.current = null;
    currentChunkIndexRef.current = 0;

    if (!Number.isFinite(chunkSize) || chunkSize <= 0) {
      reportValidationError('chunkSize must be a finite number greater than 0.');
      return;
    }

    if (!uploadUrl.trim()) {
      reportValidationError('uploadUrl must not be empty.');
      return;
    }

    sessionRef.current = {
      file,
      uploadId: createUploadId(),
      chunkSize,
      uploadUrl,
    };
    currentChunkIndexRef.current = 0;
    isPausedRef.current = false;
    isRunningRef.current = true;

    setState({
      ...initialState,
      isUploading: true,
    });

    void uploadChunks(runIdRef.current);
  }, [chunkSize, reportValidationError, uploadChunks, uploadUrl]);

  const pauseUpload = useCallback(() => {
    if (!isRunningRef.current) return;

    runIdRef.current += 1;
    isPausedRef.current = true;
    isRunningRef.current = false;
    abortControllerRef.current?.abort();
    abortControllerRef.current = null;
    setState(current => ({ ...current, isUploading: false, isPaused: true }));
  }, []);

  const resumeUpload = useCallback(() => {
    const session = sessionRef.current;

    if (!session || isRunningRef.current) return;

    const totalChunks = Math.max(1, Math.ceil(session.file.size / session.chunkSize));
    if (currentChunkIndexRef.current >= totalChunks) return;

    runIdRef.current += 1;
    isPausedRef.current = false;
    isRunningRef.current = true;
    setState(current => ({
      ...current,
      isUploading: true,
      isPaused: false,
      isError: false,
      isSuccess: false,
    }));
    void uploadChunks(runIdRef.current);
  }, [uploadChunks]);

  useEffect(() => () => {
    runIdRef.current += 1;
    isRunningRef.current = false;
    abortControllerRef.current?.abort();
  }, []);

  return {
    startUpload,
    pauseUpload,
    resumeUpload,
    retryUpload: resumeUpload,
    ...state,
  };
}
